queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?product_id ?price WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasProducts ?child ; p:hasDuty_Free_Shops ?parent . } GROUP BY ?child }
  ?child p:product_id ?product_id .
  ?child p:price ?price .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Duty_Free_Shops } }
  FILTER(?nf = ?total)
}

